module top_module(
    Y,
    A
);output Y;
    input  [11:0] A;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire [11:0] obf_inverted_inputs;

    // Generate inverted inputs
    assign obf_inverted_inputs = ~A;

    // Generate output
    assign Y = obf_inverted_inputs[11] & obf_inverted_inputs[10] & obf_inverted_inputs[9] & obf_inverted_inputs[8] & obf_inverted_inputs[7] & obf_inverted_inputs[6] & obf_inverted_inputs[5] & obf_inverted_inputs[4] & obf_inverted_inputs[3] & obf_inverted_inputs[2] & obf_inverted_inputs[1] & obf_inverted_inputs[0];

endmodule
